-- glossary-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Glossary', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Searchable reference of terms and definitions', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the term name followed by a dash and a concise one-line definition. This appears in the table row — keep it scannable."},"content":{"tips":"Start with a clear definition, then expand with context, examples, and related terms. Write for someone encountering this term for the first time."},"formatting":["Bold: the term itself on first use in the definition","Bullet lists: related terms, see-also references","Code blocks: technical terms with code examples","Italics: etymological roots or foreign-language origins","Tables: comparison of similar or commonly confused terms"],"avoid":["Circular definitions that use the term to define itself","Overly academic language when a plain definition suffices","Missing context for domain-specific terms"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":2,"max":100},"content":{"min":10,"max":5000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
